/**
 * @file fft_radix3_avx2_ct_n1_scaled.h
 * @brief DFT-3 AVX2 n1_scaled (separate is/os, output *= scale)
 *
 * FFTW-style codelet for recursive CT executor.
 * Generated by gen_radix3.py --variant ct_n1_scaled
 */

#ifndef FFT_RADIX3_AVX2_CT_CT_N1_SCALED_H
#define FFT_RADIX3_AVX2_CT_CT_N1_SCALED_H

#include <immintrin.h>

#ifndef R3A_CT_LD
#define R3A_CT_LD(p) _mm256_loadu_pd(p)
#define R3A_CT_ST(p,v) _mm256_storeu_pd((p),(v))
#endif
#define LD R3A_CT_LD
#define ST R3A_CT_ST

static __attribute__((target("avx2,fma"))) void
radix3_n1_scaled_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS    = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    const __m256d vscale = _mm256_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 4) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);

        /* DFT-3 butterfly [fwd] */
        __m256d ar=_mm256_add_pd(x1_re,x2_re), ai=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d R1r=_mm256_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm256_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm256_add_pd(x0_re,ar); x0_im=_mm256_add_pd(x0_im,ai);
        x1_re=_mm256_fmadd_pd(KS,di,R1r); x1_im=_mm256_fnmadd_pd(KS,dr,R1i);
        x2_re=_mm256_fnmadd_pd(KS,di,R1r); x2_im=_mm256_fmadd_pd(KS,dr,R1i);

        ST(&out_re[0*os+k], _mm256_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm256_mul_pd(vscale, x0_im));
        ST(&out_re[1*os+k], _mm256_mul_pd(vscale, x1_re));
        ST(&out_im[1*os+k], _mm256_mul_pd(vscale, x1_im));
        ST(&out_re[2*os+k], _mm256_mul_pd(vscale, x2_re));
        ST(&out_im[2*os+k], _mm256_mul_pd(vscale, x2_im));
    }
}

static __attribute__((target("avx2,fma"))) void
radix3_n1_scaled_bwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS    = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    const __m256d vscale = _mm256_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 4) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);

        /* DFT-3 butterfly [bwd] */
        __m256d ar=_mm256_add_pd(x1_re,x2_re), ai=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d R1r=_mm256_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm256_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm256_add_pd(x0_re,ar); x0_im=_mm256_add_pd(x0_im,ai);
        x2_re=_mm256_fmadd_pd(KS,di,R1r); x2_im=_mm256_fnmadd_pd(KS,dr,R1i);
        x1_re=_mm256_fnmadd_pd(KS,di,R1r); x1_im=_mm256_fmadd_pd(KS,dr,R1i);

        ST(&out_re[0*os+k], _mm256_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm256_mul_pd(vscale, x0_im));
        ST(&out_re[1*os+k], _mm256_mul_pd(vscale, x1_re));
        ST(&out_im[1*os+k], _mm256_mul_pd(vscale, x1_im));
        ST(&out_re[2*os+k], _mm256_mul_pd(vscale, x2_re));
        ST(&out_im[2*os+k], _mm256_mul_pd(vscale, x2_im));
    }
}


#undef LD
#undef ST

#endif /* FFT_RADIX3_AVX2_CT_CT_N1_SCALED_H */
